  1	import React, { FC, useEffect, useMemo, useState } from 'react';
  2	
  3	import { useInstanceTypeVMStore } from '@catalog/CreateFromInstanceTypes/state/useInstanceTypeVMStore';
  4	import { UseBootableVolumesValues } from '@catalog/CreateFromInstanceTypes/state/utils/types';
  5	import { CREATE_VM_TAB } from '@catalog/CreateVMHorizontalNav/constants';
  6	import { V1beta1VirtualMachineClusterPreference } from '@kubevirt-ui/kubevirt-api/kubevirt';
  7	import ListPageFilter from '@kubevirt-utils/components/ListPageFilter/ListPageFilter';
  8	import ProjectDropdown from '@kubevirt-utils/components/ProjectDropdown/ProjectDropdown';
  9	import { OPENSHIFT_OS_IMAGES_NS } from '@kubevirt-utils/constants/constants';
 10	import { ALL_PROJECTS } from '@kubevirt-utils/hooks/constants';
 11	import { useIsAdmin } from '@kubevirt-utils/hooks/useIsAdmin';
 12	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 13	import { UserSettingFavorites } from '@kubevirt-utils/hooks/useKubevirtUserSettings/utils/types';
 14	import useHideDeprecatedBootableVolumes from '@kubevirt-utils/resources/bootableresources/hooks/useHideDeprecatedBootableVolumes';
 15	import { BootableVolume } from '@kubevirt-utils/resources/bootableresources/types';
 16	import { convertResourceArrayToMap, getName } from '@kubevirt-utils/resources/shared';
 17	import { isEmpty } from '@kubevirt-utils/utils/utils';
 18	import { useListPageFilter } from '@openshift-console/dynamic-plugin-sdk';
 19	import { FormGroup, Split, SplitItem } from '@patternfly/react-core';
 20	
 21	import BootableVolumeEmptyState from '../BootableVolumeEmptyState/BootableVolumeEmptyState';
 22	
 23	import BootableVolumeListPagination from './components/BootableVolumeListPagination/BootableVolumeListPagination';
 24	import BootableVolumesPipelinesHint from './components/BootableVolumesPipelinesHint/BootableVolumesPipelinesHint';
 25	import BootableVolumeTable from './components/BootableVolumeTable/BootableVolumeTable';
 26	import ShowAllBootableVolumesButton from './components/ShowAllBootableVolumesButton/ShowAllBootableVolumesButton';
 27	import useBootVolumeColumns from './hooks/useBootVolumeColumns';
 28	import useBootVolumeFilters from './hooks/useBootVolumeFilters';
 29	import useBootVolumeSortColumns from './hooks/useBootVolumeSortColumns';
 30	import { paginationInitialStateForm, paginationInitialStateModal } from './utils/constants';
 31	import { getPaginationFromVolumeIndex } from './utils/utils';
 32	
 33	import './BootableVolumeList.scss';
 34	
 35	type BootableVolumeListProps = {
 36	  bootableVolumesData: UseBootableVolumesValues;
 37	  currentTab?: CREATE_VM_TAB;
 38	  displayShowAllButton?: boolean;
 39	  favorites: UserSettingFavorites;
 40	  preferencesData: V1beta1VirtualMachineClusterPreference[];
 41	  selectedBootableVolumeState?: [BootableVolume, (selectedVolume: BootableVolume) => void];
 42	};
 43	
 44	const BootableVolumeList: FC<BootableVolumeListProps> = ({
 45	  bootableVolumesData,
 46	  currentTab,
 47	  displayShowAllButton = false,
 48	  favorites,
 49	  preferencesData,
 50	  selectedBootableVolumeState,
 51	}) => {
 52	  const { t } = useKubevirtTranslation();
 53	  const isAdmin = useIsAdmin();
 54	
 55	  const {
 56	    instanceTypeVMState,
 57	    onSelectCreatedVolume,
 58	    setVolumeListNamespace,
 59	    volumeListNamespace,
 60	  } = useInstanceTypeVMStore();
 61	
 62	  const { pvcSource, selectedBootableVolume, volumeSnapshotSource } = instanceTypeVMState;
 63	  const { bootableVolumes, loaded, pvcSources, volumeSnapshotSources } = bootableVolumesData;
 64	
 65	  const preferencesMap = useMemo(
 66	    () => convertResourceArrayToMap(preferencesData),
 67	    [preferencesData],
 68	  );
 69	
 70	  const { activeColumns, columnLayout, loadedColumns } = useBootVolumeColumns(
 71	    volumeListNamespace,
 72	    !displayShowAllButton,
 73	  );
 74	
 75	  const filters = useBootVolumeFilters(!displayShowAllButton);
 76	
 77	  const [unfilteredData, data, onFilterChange] = useListPageFilter(bootableVolumes, filters);
 78	
 79	  const [pagination, setPagination] = useState(
 80	    displayShowAllButton ? paginationInitialStateForm : paginationInitialStateModal,
 81	  );
 82	
 83	  useHideDeprecatedBootableVolumes(onFilterChange, currentTab);
 84	
 85	  const [volumeFavorites] = favorites;
 86	
 87	  const { getSortType, sortedData, sortedPaginatedData } = useBootVolumeSortColumns(
 88	    data,
 89	    volumeFavorites,
 90	    preferencesMap,
 91	    pvcSources,
 92	    volumeSnapshotSources,
 93	    pagination,
 94	    volumeListNamespace === ALL_PROJECTS,
 95	  );
 96	
 97	  useEffect(() => {
 98	    if (!isAdmin && volumeListNamespace === ALL_PROJECTS) {
 99	      setVolumeListNamespace(OPENSHIFT_OS_IMAGES_NS);
100	    }
101	  }, [isAdmin, volumeListNamespace, setVolumeListNamespace]);
102	
103	  const displayVolumes = !isEmpty(bootableVolumes) && loaded && loadedColumns;
104	
105	  const onModalBootableVolumeSelect = (modalSelectedVolume: BootableVolume) => {
106	    const selectedVolumeIndex = sortedData?.findIndex(
107	      (volume) => getName(volume) === getName(modalSelectedVolume),
108	    );
109	
110	    setPagination(getPaginationFromVolumeIndex(selectedVolumeIndex));
111	
112	    onSelectCreatedVolume(modalSelectedVolume, pvcSource, volumeSnapshotSource);
113	  };
114	
115	  return (
116	    <>
117	      <Split className="bootable-volume-list-bar" hasGutter>
118	        <SplitItem>
119	          <FormGroup
120	            className="bootable-volume-list-bar__volume-namespace"
121	            label={t('Volumes project')}
122	          >
123	            <ProjectDropdown
124	              includeAllProjects={isAdmin}
125	              onChange={setVolumeListNamespace}
126	              selectedProject={volumeListNamespace}
127	            />
128	          </FormGroup>
129	        </SplitItem>
130	
131	        {displayVolumes && (
132	          <>
133	            <SplitItem className="bootable-volume-list-bar__filter">
134	              <ListPageFilter
135	                onFilterChange={(...args) => {
136	                  onFilterChange(...args);
137	                  setPagination((prevPagination) => ({
138	                    ...prevPagination,
139	                    endIndex: prevPagination?.perPage,
140	                    page: 1,
141	                    startIndex: 0,
142	                  }));
143	                }}
144	                columnLayout={columnLayout}
145	                data={unfilteredData}
146	                hideLabelFilter
147	                hideNameLabelFilters={!displayShowAllButton}
148	                loaded={Boolean(loaded) && loadedColumns}
149	                // nameFilter={!displayShowAllButton && "modal-name"} can remove comment once this merged https://github.com/openshift/console/pull/12438 and build into new SDK version
150	                rowFilters={filters}
151	              />
152	            </SplitItem>
153	            <SplitItem isFilled />
154	            <SplitItem className="bootable-volume-list-bar__pagination">
155	              <BootableVolumeListPagination
156	                data={data}
157	                displayShowAllButton={displayShowAllButton}
158	                pagination={pagination}
159	                setPagination={setPagination}
160	              />
161	            </SplitItem>
162	            {displayShowAllButton && (
163	              <ShowAllBootableVolumesButton
164	                bootableVolumesData={bootableVolumesData}
165	                favorites={favorites}
166	                onSelect={onModalBootableVolumeSelect}
167	                preferencesData={preferencesData}
168	              />
169	            )}
170	          </>
171	        )}
172	      </Split>
173	      {displayVolumes ? (
174	        <>
175	          <BootableVolumeTable
176	            selectedBootableVolumeState={
177	              !displayShowAllButton
178	                ? selectedBootableVolumeState
179	                : [selectedBootableVolume, onSelectCreatedVolume]
180	            }
181	            activeColumns={activeColumns}
182	            bootableVolumesData={bootableVolumesData}
183	            favorites={favorites}
184	            getSortType={getSortType}
185	            preferencesMap={preferencesMap}
186	            sortedPaginatedData={sortedPaginatedData}
187	          />
188	          <BootableVolumesPipelinesHint bootableVolumes={bootableVolumes} />
189	        </>
190	      ) : (
191	        <BootableVolumeEmptyState />
192	      )}
193	    </>
194	  );
195	};
196	
197	export default BootableVolumeList;

